import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { api } from '../utils/api';
import { timeAgo } from '../utils/formatters';
import LoadingState from '../components/LoadingState';
import ExportBar from '../components/ExportBar';
import usePageTitle from '../hooks/usePageTitle';
import { tokens } from '../styles/tokens';
import s from './LogsPage.module.css';

const C = {
  surface2: tokens.color.surfaceHover,
  textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

const LEVELS = ['all', 'info', 'warn', 'error'];
const STATIC_SOURCES = ['all', 'system', 'gateway'];

function levelColor(level) {
  if (!level) return C.textSecondary;
  const l = level.toLowerCase();
  if (l === 'error') return C.red;
  if (l === 'warn' || l === 'warning') return C.amber;
  if (l === 'info') return C.blue;
  return C.textSecondary;
}

function LevelBadge({ level }) {
  const color = levelColor(level);
  return (
    <span
      className={s.levelBadge}
      style={{ color, background: `${color}20`, border: `1px solid ${color}40` }}
    >
      {level || 'info'}
    </span>
  );
}

export default function LogsPage() {
  usePageTitle('Logs');
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [levelFilter, setLevelFilter] = useState('all');
  const [sourceFilter, setSourceFilter] = useState('all');
  const [autoScroll, setAutoScroll] = useState(true);
  const tableEndRef = useRef(null);

  const hasLoaded = useRef(false);
  const fetchLogs = useCallback(async () => {
    if (!hasLoaded.current) setLoading(true);
    setError(null);
    try {
      // Try structured logs first
      const data = await api('/system/logs');
      let entries = [];
      if (data) {
        const raw = Array.isArray(data) ? data : data.logs || data.entries || [];
        entries = Array.isArray(raw) ? raw : [];
      }
      // If no structured logs, fall back to telemetry as live log source
      if (entries.length === 0) {
        const telem = await api('/telemetry/latest');
        if (telem) {
          const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
          const bots = telem.bots || {};
          for (const [name, info] of Object.entries(bots)) {
            if (PAPER_BOTS.has(name.toLowerCase())) continue;
            entries.push({
              timestamp: info.lastHeartbeat || info.last_heartbeat || new Date().toISOString(),
              level: info.status === 'running' ? 'info' : 'warning',
              source: name,
              message: `${name}: ${info.status || 'unknown'} | positions: ${info.positions ?? '?'} | equity: $${(info.equity?.current ?? 0).toFixed(0)}`,
            });
          }
          // Add gateway info
          const gw = telem.gateway || {};
          for (const [acct, info] of Object.entries(gw)) {
            if (acct === 'All') continue;
            entries.push({
              timestamp: new Date().toISOString(),
              level: 'info',
              source: 'gateway',
              message: `${acct}: NLV $${(info?.net_liquidation ?? 0).toFixed(0)} | positions: ${info?.positions ?? 0}`,
            });
          }
        }
      }
      const normalized = entries.map((entry, i) => ({
        id: entry.id || `log-${Date.now()}-${i}`,
        timestamp: entry.timestamp || entry.lastHeartbeat || entry.last_heartbeat || new Date().toISOString(),
        level: entry.level || entry.severity || 'info',
        source: entry.source || entry.bot || entry.name || 'system',
        message: entry.message || entry.msg || entry.status || `Heartbeat from ${entry.name || 'unknown'}`,
      }));
      setLogs((prev) => {
        const existingIds = new Set(prev.map((l) => l.id));
        const newEntries = normalized.filter((e) => !existingIds.has(e.id));
        if (newEntries.length === 0) return prev;
        const combined = [...prev, ...newEntries];
        return combined.slice(-500);
      });
    } catch (err) {
      setError(err?.message || 'Failed to load logs');
    } finally {
      setLoading(false);
      hasLoaded.current = true;
    }
  }, []);

  useEffect(() => {
    fetchLogs();
    const interval = setInterval(fetchLogs, 5000);
    return () => clearInterval(interval);
  }, [fetchLogs]);

  useEffect(() => {
    if (autoScroll && tableEndRef.current) {
      tableEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, autoScroll]);

  // Build source filter options dynamically from actual log entries
  const SOURCES = useMemo(() => {
    const botSources = [...new Set(logs.map(l => l.source).filter(s => s && !['system', 'gateway'].includes(s.toLowerCase())))].sort();
    return [...STATIC_SOURCES, ...botSources];
  }, [logs]);

  const filtered = logs.filter((log) => {
    if (levelFilter !== 'all' && log.level.toLowerCase() !== levelFilter) return false;
    if (sourceFilter !== 'all' && log.source.toUpperCase() !== sourceFilter.toUpperCase()) return false;
    return true;
  });

  return (
    <LoadingState loading={loading} error={error} empty={false} type="table" onRetry={fetchLogs}>
      <div className={s.page}>
        <h1 className={s.title}>Activity Logs</h1>
        <p className={s.subtitle}>Real-time bot activity and system event log</p>

        {/* Filter bar */}
        <div className={s.filterBar}>
          <div className={s.filterGroup}>
            <span className={s.filterLabel}>Level</span>
            <select value={levelFilter} onChange={(e) => setLevelFilter(e.target.value)} className={s.filterSelect}>
              {LEVELS.map((l) => <option key={l} value={l}>{l.toUpperCase()}</option>)}
            </select>
          </div>
          <div className={s.filterGroup}>
            <span className={s.filterLabel}>Source</span>
            <select value={sourceFilter} onChange={(e) => setSourceFilter(e.target.value)} className={s.filterSelect}>
              {SOURCES.map((src) => <option key={src} value={src}>{src.toUpperCase()}</option>)}
            </select>
          </div>
          <div className={s.filterRight}>
            <span className={s.autoScrollLabel}>Auto-scroll</span>
            <button
              onClick={() => setAutoScroll(!autoScroll)}
              className={autoScroll ? s.autoScrollBtnOn : s.autoScrollBtnOff}
            >
              {autoScroll ? 'ON' : 'OFF'}
            </button>
            <span className={s.entryCount}>{filtered.length} entries</span>
          </div>
        </div>

        {/* Export bar */}
        <ExportBar data={filtered} filename="page-name-export" columns={['Timestamp', 'Level', 'Source', 'Message']} />

        {/* Log table */}
        <div className={s.tableContainer}>
          <div className={s.tableScroll}>
            {filtered.length === 0 && !loading && !error ? (
              <div className={s.emptyState}>
                <div className={s.emptyTitle}>No log entries match filters</div>
                <div className={s.emptyHint}>Adjust filters or wait for new activity</div>
              </div>
            ) : (
              <table className={s.logTable}>
                <thead>
                  <tr>
                    <th className={s.thTimestamp}>Timestamp</th>
                    <th className={s.thLevel}>Level</th>
                    <th className={s.thSource}>Source</th>
                    <th className={s.th}>Message</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((log) => (
                    <tr key={log.id} className={s.logRow}>
                      <td className={s.tdTimestamp}>
                        {new Date(log.timestamp).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                        <span className={s.tdTimeAgo}>{timeAgo(log.timestamp)}</span>
                      </td>
                      <td className={s.td}><LevelBadge level={log.level} /></td>
                      <td className={s.tdSource}>{String(log.source || '')}</td>
                      <td className={s.tdMessage}>{String(log.message || '')}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
            <div ref={tableEndRef} />
          </div>
        </div>
      </div>
    </LoadingState>
  );
}
