export function formatCurrency(val, decimals = 2) {
  if (val == null || !isFinite(val)) return '—';
  return '$' + Number(val).toLocaleString('en-US', {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  });
}

export function formatPnl(val) {
  if (val == null || !isFinite(val)) return '—';
  const prefix = val >= 0 ? '+' : '';
  return prefix + formatCurrency(val);
}

export function formatPercent(val, decimals = 1) {
  if (val == null || !isFinite(val)) return '—';
  const prefix = val >= 0 ? '+' : '';
  return prefix + Number(val).toFixed(decimals) + '%';
}

export function formatVolume(val) {
  if (val == null || !isFinite(val)) return '—';
  if (val >= 1_000_000) return (val / 1_000_000).toFixed(1) + 'M';
  if (val >= 1_000) return (val / 1_000).toFixed(1) + 'K';
  return String(val);
}

export function timeAgo(ts) {
  if (!ts) return 'never';
  // Handle Unix seconds (Python time.time()) vs milliseconds vs ISO strings
  const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : ts;
  const diff = Date.now() - new Date(ms).getTime();
  const secs = Math.floor(diff / 1000);
  if (secs < 60) return secs + 's ago';
  const mins = Math.floor(secs / 60);
  if (mins < 60) return mins + 'm ago';
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return hrs + 'h ago';
  return Math.floor(hrs / 24) + 'd ago';
}

export function pnlColor(val) {
  if (val > 0) return '#40D973';
  if (val < 0) return '#FF4D4D';
  return '#8B949E';
}
